 13→const PLAN_PADDING = 1500;
 14→const VERTICAL_PADDING = 700;
 15→const TOP_PADDING = 1100;
 16→
 17→function boundsFromPoints(points = [], fallback = { minX: -1000, maxX: 1000, minY: -1000, maxY: 1000 }) {
 18→  if (!points.length) return fallback;
 19→  return {
 20→    minX: Math.min(...points.map((point) => point.x)),
 21→    maxX: Math.max(...points.map((point) => point.x)),
 22→    minY: Math.min(...points.map((point) => point.y)),
 23→    maxY: Math.max(...points.map((point) => point.y)),
 24→  };
 25→}
 26→
 27→function expandBounds(bounds, paddingX, paddingY = paddingX) {
 28→  return {
 29→    minX: bounds.minX - paddingX,
 30→    maxX: bounds.maxX + paddingX,
 31→    minY: bounds.minY - paddingY,
 32→    maxY: bounds.maxY + paddingY,
 33→  };
 34→}
