105→function sceneBoundsToRenderBounds(scene) {
106→  return {
107→    minX: scene.bounds.minX - VERTICAL_PADDING,
108→    maxX: scene.bounds.maxX + VERTICAL_PADDING,
109→    minY: -scene.bounds.maxZ - TOP_PADDING,
110→    maxY: -scene.bounds.minZ + VERTICAL_PADDING,
111→  };
112→}
