114→function buildSectionSource(project, floor, sourceRefId) {
115→  const cuts = floor?.sectionCuts || [];
116→  const sectionCut = sourceRefId
117→    ? cuts.find(s => s.id === sourceRefId)
118→    : cuts[0] || null;
119→
120→  if (!sectionCut) {
121→    return {
